import org.junit.Test
import kotlin.test.assertEquals

class IssueReproductionTest {
    @Test
    fun testYieldWithExpiredDelay() = runBlocking {
        val results = mutableListOf<String>()
        launch {
            delay(1)
            results.add("This should be first")
        }
        Thread.sleep(200) // Much longer than 1ms
        yield()
        results.add("This should be second")

        assertEquals(listOf("This should be first", "This should be second"), results)
    }

    @Test
    fun testYieldWithExpiredDelayUndispatched() = runBlocking {
        val results = mutableListOf<String>()
        launch(start = CoroutineStart.UNDISPATCHED) {
            delay(1)
            results.add("This should be first")
        }
        Thread.sleep(200) // Much longer than 1ms
        yield()
        results.add("This should be second")

        assertEquals(listOf("This should be first", "This should be second"), results)
    }
}
