 17→    fun testNestedRunBlocking() {
 18→        runBlocking { // outer event loop
 19→            // Produce string "OK"
 20→            val ch = produce { send("OK") }
 21→            // try receive this string in a blocking way:
 22→            assertEquals("OK", runBlocking { ch.receive() }) // it should not hang here
