 28→        var completed = false
 29→        runBlocking {
 30→            launch(Dispatchers.Unconfined) {
 31→                completed = true
 32→            }
 33→            // should not go into runBlocking loop, but complete here
 34→            assertTrue(completed)
 35→        }
 36→    }
