 40→        expect(1)
 41→        GlobalScope.launch(Dispatchers.Unconfined) {
 42→            expect(2)
 43→            GlobalScope.launch(Dispatchers.Unconfined) {
 44→                // this gets scheduled into outer unconfined loop
 45→                expect(4)
 46→            }
 47→            expect(3) // ^^ executed before the above unconfined
 48→        }
 49→        finish(5)
 50→    }
