129→    class EventSync {
130→        private val waitingThread = atomic<Thread?>(null)
131→        private val fired = atomic(false)
132→
133→        fun fireEvent() {
134→            fired.value = true
135→            waitingThread.value?.let { LockSupport.unpark(it) }
136→        }
137→
138→        fun blockingAwait() {
139→            check(waitingThread.getAndSet(Thread.currentThread()) == null)
140→            while (!fired.getAndSet(false)) {
141→                val time = processNextEventInCurrentThread()
142→                LockSupport.parkNanos(time)
143→            }
144→            waitingThread.value = null
145→        }
146→    }
