303→    @Suppress("UNCHECKED_CAST")
304→    private fun enqueueImpl(task: Runnable): Boolean {
305→        _queue.loop { queue ->
306→            if (isCompleted) return false // fail fast if already completed, may still add, but queues will close
307→            when (queue) {
308→                null -> if (_queue.compareAndSet(null, task)) return true
309→                is Queue<*> -> {
310→                    when ((queue as Queue<Runnable>).addLast(task)) {
311→                        Queue.ADD_SUCCESS -> return true
312→                        Queue.ADD_CLOSED -> return false
313→                        Queue.ADD_FROZEN -> _queue.compareAndSet(queue, queue.next())
314→                    }
315→                }
316→                else -> when {
317→                    queue === CLOSED_EMPTY -> return false
318→                    else -> {
319→                        // update to full-blown queue to add one more
320→                        val newQueue = Queue<Runnable>(Queue.INITIAL_CAPACITY, singleConsumer = true)
321→                        newQueue.addLast(queue as Runnable)
322→                        newQueue.addLast(task)
323→                        if (_queue.compareAndSet(queue, newQueue)) return true
324→                    }
325→                }
326→            }
327→        }
328→    }
