413→    internal abstract class DelayedTask(
414→        /**
415→         * This field can be only modified in [scheduleTask] before putting this DelayedTask
416→         * into heap to avoid overflow and corruption of heap data structure.
417→         */
418→        @JvmField var nanoTime: Long
419→    ) : Runnable, Comparable<DelayedTask>, DisposableHandle, ThreadSafeHeapNode, SynchronizedObject() {
420→        @Volatile
421→        private var _heap: Any? = null // null | ThreadSafeHeap | DISPOSED_TASK
422→
423→        override var heap: ThreadSafeHeap<*>?
424→            get() = _heap as? ThreadSafeHeap<*>
425→            set(value) {
426→                require(_heap !== DISPOSED_TASK) // this can never happen, it is always checked before adding/removing
427→                _heap = value
428→            }
429→
430→        override var index: Int = -1
431→
432→        override fun compareTo(other: DelayedTask): Int {
433→            val dTime = nanoTime - other.nanoTime
434→            return when {
435→                dTime > 0 -> 1
436→                dTime < 0 -> -1
437→                else -> 0
438→            }
439→        }
440→
441→        fun timeToExecute(now: Long): Boolean = now - nanoTime >= 0L
442→
443→        fun scheduleTask(now: Long, delayed: DelayedTaskQueue, eventLoop: EventLoopImplBase): Int = synchronized<Int>(this) {
444→            if (_heap === DISPOSED_TASK) return SCHEDULE_DISPOSED // don't add -- was already disposed
445→            delayed.addLastIf(this) { firstTask ->
446→                if (eventLoop.isCompleted) return SCHEDULE_COMPLETED // non-local return from scheduleTask
447→                /**
448→                 * We are about to add new task and we have to make sure that [DelayedTaskQueue]
449→                 * invariant is maintained. The code in this lambda is additionally executed under
450→                 * the lock of [DelayedTaskQueue] and working with [DelayedTaskQueue.timeNow] here is thread-safe.
451→                 */
452→                if (firstTask == null) {
453→                    /**
454→                     * When adding the first delayed task we simply update queue's [DelayedTaskQueue.timeNow] to
455→                     * the current now time even if that means "going backwards in time". This makes the structure
456→                     * self-correcting in spite of wild jumps in `nanoTime()` measurements once all delayed tasks
457→                     * are removed from the delayed queue for execution.
458→                     */
459→                    delayed.timeNow = now
460→                } else {
461→                    /**
462→                     * Carefully update [DelayedTaskQueue.timeNow] so that it does not sweep past first's tasks time
463→                     * and only goes forward in time. We cannot let it go backwards in time or invariant can be
464→                     * violated for tasks that were already scheduled.
465→                     */
466→                    val firstTime = firstTask.nanoTime
467→                    // compute min(now, firstTime) using a wrap-safe check
468→                    val minTime = if (firstTime - now >= 0) now else firstTime
469→                    // update timeNow only when going forward in time
470→                    if (minTime - delayed.timeNow > 0) delayed.timeNow = minTime
471→                }
472→                /**
473→                 * Here [DelayedTaskQueue.timeNow] was already modified and we have to double-check that newly added
474→                 * task does not violate [DelayedTaskQueue] invariant because of that. Note also that this scheduleTask
475→                 * function can be called to reschedule from one queue to another and this might be another reason
476→                 * where new task's time might now violate invariant.
477→                 * We correct invariant violation (if any) by simply changing this task's time to now.
478→                 */
479→                if (nanoTime - delayed.timeNow < 0) nanoTime = delayed.timeNow
480→                true
481→            }
482→            return SCHEDULE_OK
483→        }
484→
485→        final override fun dispose(): Unit = synchronized(this) {
486→            val heap = _heap
487→            if (heap === DISPOSED_TASK) return // already disposed
488→            (heap as? DelayedTaskQueue)?.remove(this) // remove if it is in heap (first)
489→            _heap = DISPOSED_TASK // never add again to any heap
490→        }
491→
492→        override fun toString(): String = "Delayed[nanos=$nanoTime]"
493→    }
